export const runtime = "nodejs";
export const dynamic = "force-dynamic";

const corsHeaders = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Methods": "GET, POST, PUT, DELETE, PATCH, OPTIONS",
  "Access-Control-Allow-Headers": "Authorization, Content-Type"
};

function jsonResponse(body: unknown, status: number) {
  return Response.json(body, {
    status,
    headers: corsHeaders
  });
}

async function handle(request: Request) {
  if (request.method === "OPTIONS") {
    return new Response(null, {
      status: 204,
      headers: corsHeaders
    });
  }

  try {
    const url = new URL(request.url);
    const path = url.searchParams.get("path");
    const apiVersion = url.searchParams.get("v") === "3" ? "v3" : "v2";

    if (!path || !path.startsWith("/")) {
      return jsonResponse(
        { error: "Missing or invalid ?path= parameter (must start with /)" },
        400
      );
    }

    const passthrough = new URLSearchParams();
    url.searchParams.forEach((value, key) => {
      if (key !== "path" && key !== "v") passthrough.append(key, value);
    });

    const queryString = passthrough.toString();
    const target = `https://api.clickup.com/api/${apiVersion}${path}${
      queryString ? `?${queryString}` : ""
    }`;

    const auth = request.headers.get("authorization");
    if (!auth) {
      return jsonResponse(
        { error: "Missing Authorization header (ClickUp personal token)" },
        401
      );
    }

    const body =
      request.method === "GET" || request.method === "HEAD"
        ? undefined
        : await request.text();

    const upstream = await fetch(target, {
      method: request.method,
      headers: {
        Authorization: auth,
        "Content-Type": "application/json",
        Accept: "application/json"
      },
      body
    });

    const text = await upstream.text();
    const headers = new Headers(corsHeaders);
    const contentType = upstream.headers.get("content-type");
    if (contentType) headers.set("Content-Type", contentType);

    return new Response(text, {
      status: upstream.status,
      headers
    });
  } catch (error) {
    console.error("[api/clickup] error:", error);
    return jsonResponse(
      {
        error: "Proxy error",
        detail: error instanceof Error ? error.message : String(error)
      },
      502
    );
  }
}

export const GET = handle;
export const POST = handle;
export const PUT = handle;
export const PATCH = handle;
export const DELETE = handle;
export const OPTIONS = handle;
